func:parse_float = flt64(int8->:str) {
if (str == NULL) {
        return 0.0;
    }

    flt64:result = 0.0f64;
    flt64:sign = 1.0f64;
    int32:i = 0i32;

    // Skip whitespace
    while (str[i] == 32 || str[i] == 9) {
        i = i + 1;
    }

    // Handle sign
    if (str[i] == 45) {
        sign = (0.0 - 1.0);
        i = i + 1;
    } else {
        if (str[i] == 43) {
            i = i + 1;
        } else {
            // no sign
        }
    }

    // Parse integer part
    while (str[i] >= 48 && str[i] <= 57) {
        flt64:digit = (str[i] - 48);
        result = (result * 10.0) + digit;
        i = i + 1;
    }

    // Parse decimal part if present
    if (str[i] == 46) {
        i = i + 1;
        flt64:divisor = 10.0;

        while (str[i] >= 48 && str[i] <= 57) {
            flt64:digit = (str[i] - 48);
            result = result + (digit / divisor);
            divisor = divisor * 10.0;
            i = i + 1;
        }
    } else {
        // no decimal
    }

    return result * sign;
};
}
