func:next_token = Token(Tokenizer->:tok) {
skip_whitespace(tok) ? NIL;

    // Save position for token
    int32:tok_line = (<-tok).line;
    int32:tok_col = (<-tok).column;

    int8:ch = peek(tok) ? 0i8;

    // EOF
    if (ch == 0i8) {
        Token:t = Token { type: 0, line: tok_line, column: tok_col };  // TOK_EOF
        pass(t);
    } else {
        // Structural characters
        if (ch == 123i8) {  // {
            advance(tok) ? 0i8;
            Token:t = Token { type: 1, line: tok_line, column: tok_col };  // TOK_LBRACE
            pass(t);
        } else {
            if (ch == 125i8) {  // }
                advance(tok) ? 0i8;
                Token:t = Token { type: 2, line: tok_line, column: tok_col };  // TOK_RBRACE
                pass(t);
            } else {
                if (ch == 91i8) {  // [
                    advance(tok) ? 0i8;
                    Token:t = Token { type: 3, line: tok_line, column: tok_col };  // TOK_LBRACKET
                    pass(t);
                } else {
                    if (ch == 93i8) {  // ]
                        advance(tok) ? 0i8;
                        Token:t = Token { type: 4, line: tok_line, column: tok_col };  // TOK_RBRACKET
                        pass(t);
