func:parse_int_range = int32(int8->:str, int32:start, int32:length) {
if (str == NULL || length <= 0) {
        return 0;
    }

    int32:result = 0i32;
    int32:sign = 1i32;
    int32:i = start;
    int32:end_pos = start + length;

    // Handle sign
    if (i < end_pos) {
        if (str[i] == 45) {
            sign = (0 - 1);
            i = i + 1;
        } else {
            if (str[i] == 43) {
                i = i + 1;
            } else {
                // no sign
            }
        }
    } else {
        return 0;
    }

    // Parse digits
    while (i < end_pos && str[i] >= 48 && str[i] <= 57) {
        int32:digit = str[i] - 48;
        result = (result * 10) + digit;
        i = i + 1;
    }

    return result * sign;
};
}
