    while (i < pos) {
        val = (val / 2);
        i = (i + 1);
    }

    int32:bit = (val - ((val / 2) * 2));  // Check lowest bit
    bool:result = false;
    bool:is_set = (bit == 1);
    if (is_set) {
        result = true;
    } else {
        result = false;
    }
    pass(result);
};

